-- TravelTech Hub - seed data
--
-- Generated by scripts/generate-seed.mjs from src/config/categories.js and
-- src/data/*.json. Do not hand-edit - rerun `npm run seed:generate` instead.
--
-- Run this against a project that already has 001_initial_schema.sql
-- applied, using a role that bypasses RLS (the Supabase SQL Editor and
-- `supabase db push` both connect as the "postgres" role, which does).
--
-- Idempotent: every listing is upserted on its unique (legacy_id, category_id)
-- pair (a handful of vendors are legitimately cross-listed under two
-- categories in the source data), and each
-- listing's child rows (features/usps/products/target markets) are deleted
-- and reinserted in the same statement, so rerunning this file never
-- creates duplicates.
--
-- Data-quality note: the source JSON files explicitly disclaim that email
-- and phone values are plausible placeholder-format examples, not verified
-- contact details (see the "_comment" field in each src/data/*.json file).
-- To avoid ever presenting placeholder data as real, every seeded listing
-- gets email = null, phone = null, and contact_verified = false regardless
-- of what the source JSON contained. Real websites are preserved. Vendors
-- keep showing logoInitials in the UI until a real logo is uploaded via
-- Supabase Storage.
--
-- Categories: 20   Listings: 337

begin;

insert into public.categories (id, name, short_name, route, description, color, icon, display_order, is_active)
values
  ('pms', 'Property Management Systems', 'PMS', '/pms', 'Software that runs the day-to-day operations of hotels and properties - reservations, housekeeping, billing and front-desk operations.', 'indigo', 'Building2', 0, true),
  ('crs', 'Central Reservation Systems', 'CRS', '/crs', 'The backbone systems that manage rates, inventory and availability across a hotel or chain’s many distribution channels.', 'teal', 'Server', 1, true),
  ('airline-aggregators', 'Airline Aggregators', 'Airlines', '/airline-aggregators', 'GDS and API platforms that aggregate airline fares and inventory for travel agencies, OTAs and corporate booking tools.', 'sky', 'Plane', 2, true),
  ('hotel-aggregators', 'Hotel Aggregators', 'Hotels', '/hotel-aggregators', 'Wholesale hotel supply platforms giving resellers API access to global accommodation inventory and net rates.', 'amber', 'Hotel', 3, true),
  ('rail-aggregators', 'Rail Aggregators', 'Rail', '/rail-aggregators', 'API platforms aggregating rail operator content across countries so resellers can sell rail as easily as flights.', 'emerald', 'TrainFront', 4, true),
  ('cruise-aggregators', 'Liveaboard & Cruise Aggregators', 'Cruise', '/cruise-aggregators', 'Booking and distribution platforms specialising in cruise lines, liveaboard diving trips and river cruises.', 'cyan', 'Ship', 5, true),
  ('channel-managers', 'Channel Managers', 'Channel Mgrs', '/channel-managers', 'Tools that sync rates, availability and inventory in real time across every OTA and channel a property sells on.', 'violet', 'Share2', 6, true),
  ('b2b-wholesalers', 'B2B Wholesalers', 'Wholesalers', '/b2b-wholesalers', 'Bed banks and wholesale travel suppliers providing net-rate accommodation and ancillary content to trade partners.', 'orange', 'Warehouse', 7, true),
  ('booking-distribution', 'Booking & Distribution Platforms', 'Booking', '/booking-distribution', 'End-to-end booking engines and distribution technology connecting suppliers, resellers and travel sellers.', 'rose', 'Network', 8, true),
  ('ota', 'OTA & Travel Aggregators', 'OTA', '/ota', 'Consumer-facing online travel agencies and metasearch aggregators selling flights, hotels and packages directly.', 'blue', 'Globe2', 9, true),
  ('tour-operators', 'Tour Operators with Own API Distribution', 'Tour Ops', '/tour-operators', 'Tour and package operators that expose their own inventory via API for B2B resale by agents and OTAs.', 'lime', 'Map', 10, true),
  ('rail-meta', 'Rail Meta Booking Engines', 'Rail Meta', '/rail-meta', 'Metasearch and booking engines comparing rail fares across multiple operators and countries in one interface.', 'fuchsia', 'Route', 11, true),
  ('hotel-reservations', 'Hotel Reservations Software', 'Reservations', '/hotel-reservations', 'Reservation platforms that let independent hotels and small chains manage bookings, rates and availability directly.', 'red', 'CalendarCheck', 12, true),
  ('hotel-management-software', 'Hotel Management Software', 'Hotel Mgmt', '/hotel-management-software', 'All-in-one operational software covering front desk, housekeeping, POS and back-office management for properties.', 'yellow', 'LayoutDashboard', 13, true),
  ('revenue-management', 'Revenue Management Systems', 'Revenue Mgmt', '/revenue-management', 'Dynamic pricing and forecasting engines that optimise hotel room rates against demand, competitors and market data.', 'green', 'LineChart', 14, true),
  ('booking-engine', 'Booking Engine', 'Booking Engine', '/booking-engine', 'Direct booking widgets and engines hotels embed on their own websites to convert visitors without OTA commission.', 'purple', 'MousePointerClick', 15, true),
  ('hotel-crm-email-marketing', 'Hotel CRM & Email Marketing', 'CRM & Email', '/hotel-crm-email-marketing', 'Guest data platforms and email/CRM tools that help hotels build guest profiles and drive repeat direct bookings.', 'pink', 'Mail', 16, true),
  ('guest-messaging', 'Guest Messaging Software', 'Messaging', '/guest-messaging', 'Two-way SMS, WhatsApp and chat platforms that let hotel staff communicate with guests before, during and after their stay.', 'stone', 'MessageCircle', 17, true),
  ('hotel-guest-apps', 'Hotel Guest Apps', 'Guest Apps', '/hotel-guest-apps', 'Mobile and web apps offering guests digital check-in, room service, concierge requests and in-stay information.', 'gray', 'Smartphone', 18, true),
  ('keyless-entry', 'Hotel Keyless Entry Systems', 'Keyless Entry', '/keyless-entry', 'Mobile and RFID access control systems letting guests unlock hotel rooms without a physical key card.', 'slate', 'KeyRound', 19, true)
on conflict (id) do update set
  name = excluded.name,
  short_name = excluded.short_name,
  route = excluded.route,
  description = excluded.description,
  color = excluded.color,
  icon = excluded.icon,
  display_order = excluded.display_order,
  is_active = excluded.is_active;

do $seed_listing$
declare
  v_listing_id uuid;
begin
  insert into public.listings (
    legacy_id, owner_id, category_id, name, slug, logo_initials, description,
    pricing_model, price_range, email, phone, website, headquarters, founded,
    status, featured, verified, contact_verified, submitted_at, approved_at
  ) values (
    'oracle-opera-cloud', null, 'pms', 'Oracle OPERA Cloud', 'oracle-opera-cloud',
    'OC', 'Oracle OPERA Cloud is a cloud-native property management system used by hotel chains and independent properties worldwide to manage reservations, front desk, housekeeping, and revenue operations. It integrates with a large ecosystem of sales and catering, distribution, and payment applications through Oracle''s OHIP APIs.',
    'Enterprise/Custom', '$$$', null, null,
    'https://www.oracle.com/hospitality/', 'Austin, United States', 1977,
    'approved', false, false, false, now(), now()
  )
  on conflict (legacy_id, category_id) do update set
    category_id = excluded.category_id,
    name = excluded.name,
    slug = excluded.slug,
    logo_initials = excluded.logo_initials,
    description = excluded.description,
    pricing_model = excluded.pricing_model,
    price_range = excluded.price_range,
    email = excluded.email,
    phone = excluded.phone,
    website = excluded.website,
    headquarters = excluded.headquarters,
    founded = excluded.founded,
    status = excluded.status,
    contact_verified = excluded.contact_verified
  returning id into v_listing_id;

  delete from public.listing_features where listing_id = v_listing_id;
  insert into public.listing_features (listing_id, value, display_order) values
    (v_listing_id, 'Cloud-based PMS', 0),
    (v_listing_id, 'Mobile check-in/checkout', 1),
    (v_listing_id, 'Multi-property management', 2),
    (v_listing_id, 'Open API platform (OHIP)', 3),
    (v_listing_id, 'Integrated POS', 4),
    (v_listing_id, 'Revenue management integration', 5);

  delete from public.listing_usps where listing_id = v_listing_id;
  insert into public.listing_usps (listing_id, value, display_order) values
    (v_listing_id, 'Deep enterprise-grade scalability', 0),
    (v_listing_id, 'Extensive global partner ecosystem', 1),
    (v_listing_id, 'Trusted by major hotel chains', 2);

  delete from public.listing_products where listing_id = v_listing_id;
  insert into public.listing_products (listing_id, value, display_order) values
    (v_listing_id, 'OPERA Cloud PMS', 0),
    (v_listing_id, 'OPERA Reservation System', 1),
    (v_listing_id, 'Sales & Catering', 2),
    (v_listing_id, 'Hospitality Integration Platform', 3);

  delete from public.listing_target_markets where listing_id = v_listing_id;
  insert into public.listing_target_markets (listing_id, value) values
    (v_listing_id, 'Global'),
    (v_listing_id, 'North America'),
    (v_listing_id, 'Europe'),
    (v_listing_id, 'APAC');

end $seed_listing$;


